const NORMALIZED_TEAM_CONFEDERATIONS = Object.entries(TEAM_CONFEDERATIONS).reduce(
  (acc, [team, confed]) => {
    acc[normalizeTeamInput(team)] = confed;
    return acc;
  },
  {}
);

export const getTeamConfed = (input) => {
  if (!input) return "";
  const canonical = resolveCanonicalTeam(input);
  return (
    TEAM_CONFEDERATIONS[canonical] ||
    NORMALIZED_TEAM_CONFEDERATIONS[normalizeTeamInput(canonical)] ||
    NORMALIZED_TEAM_CONFEDERATIONS[normalizeTeamInput(input)] ||
    ""
  );
};
